nodes.notes:
Vast.ai - search GPU offers, rent and manage cloud GPU instances.

Actions:
  search_offers - search available GPU rental offers. Filter by gpu_name, num_gpus, max_price, min_ram.
  list_instances - list all your rented GPU instances with status.
  show_instance - get detailed info for a specific instance. Requires instance_id.
  get_balance - check your Vast.ai account balance.
  create_instance - rent a GPU from an offer. Requires offer_id. Default image: vastai/pytorch.
  start_instance - start a stopped instance. Requires instance_id.
  stop_instance - stop a running instance. Requires instance_id.
  reboot_instance - reboot an instance. Requires instance_id.
  destroy_instance - permanently destroy an instance. Requires instance_id. Irreversible.
  get_logs - get container logs for an instance. Requires instance_id.
  label_instance - set a label on an instance. Requires instance_id and label.

Rules:
- instance_id comes from list_instances or show_instance. Never fabricate IDs.
- offer_id comes from search_offers. Always search first before creating.
- For create_instance, image is a Docker image like "nvidia/cuda:12.1.0-devel-ubuntu22.04" or "pytorch/pytorch:latest".
- destroy_instance is permanent and irreversible. Confirm with user before calling.

Chaining:
- "Find me a cheap 4090" -> search_offers gpu_name "4090"
- "Rent the cheapest one" -> create_instance with offer_id from search
- "What's running?" -> list_instances
- "Show me instance 12345" -> show_instance
- "Stop that instance" -> stop_instance with instance_id from context
- "Check my balance" -> get_balance

---schema
{
  "action": {
    "type": "string",
    "description": "One of: search_offers, list_instances, show_instance, get_balance, create_instance, start_instance, stop_instance, reboot_instance, destroy_instance, get_logs, label_instance",
    "required": true
  },
  "instance_id": {
    "type": "integer",
    "description": "Vast.ai instance ID. For: show_instance, start_instance, stop_instance, reboot_instance, destroy_instance, get_logs, label_instance"
  },
  "offer_id": {
    "type": "integer",
    "description": "Vast.ai offer ID from search_offers. For: create_instance"
  },
  "gpu_name": {
    "type": "string",
    "description": "GPU model name, e.g. 4090, 3090, A100, H100. For: search_offers"
  },
  "num_gpus": {
    "type": "integer",
    "description": "Minimum number of GPUs. For: search_offers"
  },
  "max_price": {
    "type": "number",
    "description": "Maximum price in $/hour. For: search_offers"
  },
  "min_ram": {
    "type": "integer",
    "description": "Minimum GPU RAM in GB. For: search_offers"
  },
  "image": {
    "type": "string",
    "description": "Docker image to run. Default: vastai/pytorch. For: create_instance"
  },
  "disk": {
    "type": "integer",
    "description": "Disk space in GB. Default 100. For: create_instance"
  },
  "label": {
    "type": "string",
    "description": "Label for the instance. For: create_instance, label_instance"
  },
  "limit": {
    "type": "integer",
    "description": "Max results. Default 10. For: search_offers"
  }
}

parameters.jsCode:
// Parse input
let data;
const input = $input.item.json;

if (typeof input.body === 'string') {
  data = JSON.parse(input.body);
} else if (typeof input.body === 'object') {
  data = input.body;
} else {
  data = input;
}

const action = (data.action || '').toLowerCase().trim();

if (!action) {
  return [{ json: { error: true, message: 'Action is required. Use one of: search_offers, list_instances, show_instance, get_balance, create_instance, start_instance, stop_instance, reboot_instance, destroy_instance, get_logs, label_instance.' } }];
}

// Determine category
const categoryMap = {
  search_offers: 'read',
  list_instances: 'read',
  show_instance: 'read',
  get_balance: 'read',
  create_instance: 'write',
  start_instance: 'manage',
  stop_instance: 'manage',
  reboot_instance: 'manage',
  destroy_instance: 'manage',
  get_logs: 'manage',
  label_instance: 'manage'
};

const category = categoryMap[action] || '';

if (!category) {
  return [{ json: { error: true, message: `Unknown action: ${action}. Use one of: search_offers, list_instances, show_instance, get_balance, create_instance, start_instance, stop_instance, reboot_instance, destroy_instance, get_logs, label_instance.` } }];
}

const instance_id = parseInt(data.instance_id) || null;
const offer_id = parseInt(data.offer_id) || null;
const gpu_name = data.gpu_name || '';
const num_gpus = parseInt(data.num_gpus) || 1;
const max_price = parseFloat(data.max_price) || null;
const min_ram = parseInt(data.min_ram) || null;
const image = data.image || '';
const disk = parseInt(data.disk) || 20;
const label = data.label || '';
const limit = parseInt(data.limit) || 10;

return [{
  json: {
    action,
    category,
    instance_id,
    offer_id,
    gpu_name,
    num_gpus,
    max_price,
    min_ram,
    image,
    disk,
    label,
    limit
  }
}];

const data = $input.item.json;
const gpu_name = data.gpu_name || '';
const num_gpus = data.num_gpus || 1;
const max_price = data.max_price || null;
const min_ram = data.min_ram || null;
const limit = data.limit || 10;

// Build the query filter
const regionEnv = '${VASTAI_SEARCH_REGION}' || 'US,CA';
const regions = regionEnv.split(',').map(r => r.trim()).filter(Boolean);

const q = {
  verified: { eq: true },
  rentable: { eq: true },
  type: 'on-demand',
  geolocation: { in: regions },
  direct_port_count: { gte: 1 },
  order: [['dph_total', 'asc']],
  limit: limit
};

// GPU name mapping (API uses spaces, e.g. 'RTX 4090')
if (gpu_name) {
  const nameMap = {
    '4090': 'RTX 4090',
    'rtx4090': 'RTX 4090',
    'rtx 4090': 'RTX 4090',
    '3090': 'RTX 3090',
    'rtx3090': 'RTX 3090',
    'rtx 3090': 'RTX 3090',
    '3080': 'RTX 3080',
    'rtx3080': 'RTX 3080',
    'rtx 3080': 'RTX 3080',
    '3080 ti': 'RTX 3080 Ti',
    '4080': 'RTX 4080',
    'rtx4080': 'RTX 4080',
    'rtx 4080': 'RTX 4080',
    '4070': 'RTX 4070',
    '4070 ti': 'RTX 4070 Ti',
    '4060': 'RTX 4060',
    '3060': 'RTX 3060',
    '3070 ti': 'RTX 3070 Ti',
    'a100': 'A100',
    'a6000': 'RTX A6000',
    'a40': 'A40',
    'h100': 'H100',
    'l40': 'L40',
    'l40s': 'L40S',
    'a10': 'A10',
    '5090': 'RTX 5090',
    '5080': 'RTX 5080'
  };
  const mapped = nameMap[gpu_name.toLowerCase()] || gpu_name;
  q.gpu_name = { in: [mapped] };
}

// Num GPUs
if (num_gpus > 1) {
  q.num_gpus = { gte: num_gpus };
}

// Max price
if (max_price) {
  q.dph_total = { lte: max_price };
}

// Min RAM (user gives GB, API wants MB)
if (min_ram) {
  q.gpu_ram = { gte: min_ram * 1024 };
}

return [{ json: { searchBody: q, limit: limit } }];

const response = $input.item.json;
const offers = response.offers || [];
const limit = $('Build Search Body').item.json.limit || 10;

if (!offers || offers.length === 0) {
  return [{ json: { message: 'No GPU offers found matching your criteria. Try broadening your search.', offers: [] } }];
}

const limited = offers.slice(0, limit);

const formatted = limited.map((o, idx) => {
  const gpuRamGB = o.gpu_ram ? Math.round(o.gpu_ram / 1024) : 0;
  const priceStr = o.dph_total ? '$' + o.dph_total.toFixed(2) + '/hr' : 'N/A';
  return {
    number: idx + 1,
    offer_id: o.id,
    gpu_name: o.gpu_name || 'Unknown',
    num_gpus: o.num_gpus || 1,
    gpu_ram_gb: gpuRamGB,
    price_per_hour: priceStr,
    dph_total: o.dph_total,
    geolocation: o.geolocation || 'Unknown',
    reliability: o.reliability ? (o.reliability * 100).toFixed(1) + '%' : 'N/A',
    inet_down: o.inet_down ? o.inet_down.toFixed(0) + ' Mbps' : 'N/A',
    cuda_vers: o.cuda_max_good || 'N/A'
  };
});

let message = `Found ${offers.length} GPU offer${offers.length === 1 ? '' : 's'}. `;
formatted.forEach(o => {
  message += `${o.number}. ${o.gpu_name}`;
  if (o.num_gpus > 1) message += ` x${o.num_gpus}`;
  message += ` - ${o.price_per_hour}, ${o.gpu_ram_gb}GB RAM, ${o.geolocation}. `;
});

return [{ json: { message: message.trim(), count: offers.length, offers: formatted } }];

const response = $input.item.json;
const instances = response.instances || [];

if (!instances || instances.length === 0) {
  return [{ json: { message: 'You have no active instances.', count: 0, instances: [] } }];
}

const formatted = instances.map(i => ({
  id: i.id,
  status: i.actual_status || i.status_msg || 'unknown',
  gpu_name: i.gpu_name || 'Unknown',
  num_gpus: i.num_gpus || 1,
  label: i.label || '',
  price_per_hour: i.dph_total ? '$' + i.dph_total.toFixed(2) + '/hr' : 'N/A'
}));

const running = formatted.filter(i => i.status === 'running').length;
const stopped = formatted.filter(i => i.status === 'stopped' || i.status === 'exited').length;

let message = `You have ${instances.length} instance${instances.length === 1 ? '' : 's'}.`;
if (running > 0) message += ` ${running} running.`;
if (stopped > 0) message += ` ${stopped} stopped.`;

return [{ json: { message, count: instances.length, instances: formatted } }];

const raw = $input.item.json;
const i = raw.instances || raw;

const gpuRamGB = i.gpu_ram ? Math.round(i.gpu_ram / 1024) : 0;
const priceStr = i.dph_total ? '$' + i.dph_total.toFixed(2) + '/hr' : 'N/A';
const uptimeHrs = i.duration ? Math.round(i.duration / 3600) : 0;

const detail = {
  id: i.id,
  status: i.actual_status || i.status_msg || 'unknown',
  gpu_name: i.gpu_name || 'Unknown',
  num_gpus: i.num_gpus || 1,
  gpu_ram_gb: gpuRamGB,
  disk_space_gb: i.disk_space ? Math.round(i.disk_space) : 0,
  ssh_host: i.ssh_host || '',
  ssh_port: i.ssh_port || '',
  price_per_hour: priceStr,
  label: i.label || '',
  uptime_hours: uptimeHrs,
  image: i.image_uuid || '',
  public_ip: i.public_ipaddr || '',
  geolocation: i.geolocation || ''
};

let message = `Instance ${i.id}: ${detail.gpu_name}`;
if (detail.num_gpus > 1) message += ` x${detail.num_gpus}`;
message += `, ${detail.gpu_ram_gb}GB RAM. Status: ${detail.status}. Price: ${priceStr}.`;
if (detail.label) message += ` Label: ${detail.label}.`;
if (detail.ssh_host && detail.ssh_port) message += ` SSH: ssh -p ${detail.ssh_port} root@${detail.ssh_host}.`;
if (detail.geolocation) message += ` Location: ${detail.geolocation}.`;
if (uptimeHrs > 0) message += ` Uptime: ${uptimeHrs} hours.`;

return [{ json: { message, instance: detail } }];

const data = $input.item.json;

const credit = data.credit || data.balance || 0;
const balance = typeof credit === 'number' ? credit.toFixed(2) : credit;

return [{ json: { message: `Your Vast.ai balance is $${balance}.`, balance: parseFloat(balance) } }];

const data = $input.item.json;

if (!data.offer_id) {
  return [{ json: { error: true, message: 'offer_id is required for create_instance. Search for offers first using search_offers.' } }];
}

// Default image if not specified
if (!data.image) {
  data.image = 'vastai/pytorch:@vastai-automatic-tag';
}

return [{ json: data }];

const result = $input.item.json;
const contractId = result.new_contract || result.contract_id || result.id || 'unknown';

return [{ json: { message: `Instance created. Contract ID: ${contractId}. It will be ready in a few moments.`, contract_id: contractId, success: true } }];

const result = $input.item.json;
const instanceId = $('Parse Parameters').item.json.instance_id;

let logs = result.result || result.logs || result.log || JSON.stringify(result);

if (typeof logs === 'object') {
  logs = JSON.stringify(logs);
}

// Truncate if very long
if (logs.length > 3000) {
  logs = logs.substring(logs.length - 3000);
  logs = '... (truncated) ...\n' + logs;
}

return [{ json: { message: `Logs for instance ${instanceId}:`, instance_id: instanceId, logs: logs } }];

const instanceId = $('Parse Parameters').item.json.instance_id;
const label = $('Parse Parameters').item.json.label;
return [{ json: { message: `Instance ${instanceId} labeled as '${label}'.`, instance_id: instanceId, label: label, success: true } }];

const errorData = $input.item.json;

// If it's already a formatted error from a Code node
if (errorData.error === true && errorData.message) {
  return [{ json: { message: errorData.message, error: true } }];
}

// Otherwise it's from an n8n node error output
let errorMsg = errorData.message || errorData.error || 'Unknown error';

if (typeof errorMsg === 'object') {
  errorMsg = errorMsg.message || JSON.stringify(errorMsg);
}

// Make error voice-friendly
if (errorMsg.includes('authorization') || errorMsg.includes('403') || errorMsg.includes('401') || errorMsg.includes('Unauthorized')) {
  errorMsg = 'Vast.ai authentication failed. Please check your API key.';
} else if (errorMsg.includes('rate limit') || errorMsg.includes('429')) {
  errorMsg = 'Vast.ai rate limit reached. Try again in a few minutes.';
} else if (errorMsg.includes('404') || errorMsg.includes('Not Found') || errorMsg.includes('not found')) {
  errorMsg = 'Resource not found. The instance or offer ID may be invalid.';
} else if (errorMsg.includes('400') || errorMsg.includes('Bad Request')) {
  errorMsg = 'Bad request. Please check your parameters.';
} else if (errorMsg.includes('402') || errorMsg.includes('insufficient')) {
  errorMsg = 'Insufficient balance. Please add funds to your Vast.ai account.';
} else if (errorMsg.includes('ECONNREFUSED') || errorMsg.includes('ETIMEDOUT')) {
  errorMsg = 'Cannot connect to Vast.ai. Check your internet connection.';
}

return [{ json: { message: 'Vast.ai error: ' + errorMsg, error: true } }];
